module InvokeAssistantResponse =
  struct
    type nonrec t =
      {
      body: ResponseStream.t option ;
      conversationId: ConversationId.t option
        [@ocaml.doc
          "The ID of the conversation, in UUID format. This ID uniquely identifies the conversation within IoT SiteWise."]}
    type nonrec error =
      [ `AccessDeniedException of AccessDeniedException.t 
      | `ConflictingOperationException of ConflictingOperationException.t 
      | `InternalFailureException of InternalFailureException.t 
      | `InvalidRequestException of InvalidRequestException.t 
      | `LimitExceededException of LimitExceededException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ThrottlingException of ThrottlingException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?body =
      fun ?conversationId -> fun () -> { body; conversationId }
    let error_of_json name json =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_json json)
      | "ConflictingOperationException" ->
          `ConflictingOperationException
            (ConflictingOperationException.of_json json)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_json json)
      | "InvalidRequestException" ->
          `InvalidRequestException (InvalidRequestException.of_json json)
      | "LimitExceededException" ->
          `LimitExceededException (LimitExceededException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "ConflictingOperationException" ->
          `ConflictingOperationException
            (ConflictingOperationException.of_xml xml)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_xml xml)
      | "InvalidRequestException" ->
          `InvalidRequestException (InvalidRequestException.of_xml xml)
      | "LimitExceededException" ->
          `LimitExceededException (LimitExceededException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `ConflictingOperationException e ->
          `Assoc
            [("error", (`String "ConflictingOperationException"));
            ("details", (ConflictingOperationException.to_json e))]
      | `InternalFailureException e ->
          `Assoc
            [("error", (`String "InternalFailureException"));
            ("details", (InternalFailureException.to_json e))]
      | `InvalidRequestException e ->
          `Assoc
            [("error", (`String "InvalidRequestException"));
            ("details", (InvalidRequestException.to_json e))]
      | `LimitExceededException e ->
          `Assoc
            [("error", (`String "LimitExceededException"));
            ("details", (LimitExceededException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ThrottlingException e ->
          `Assoc
            [("error", (`String "ThrottlingException"));
            ("details", (ThrottlingException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let of_header_and_body =
      ((fun (xs, pipe) ->
          make ?body:(Some pipe)
            ?conversationId:(Option.map
                               ((List.Assoc.find ~equal:String.Caseless.equal)
                                  xs
                                  "x-amz-iotsitewise-assistant-conversation-id")
                               ~f:ConversationId.of_string) ())
      [@warning "-27"])
    let to_value x =
      structure_to_value
        [("body", (Option.map x.body ~f:ResponseStream.to_value));
        ("x-amz-iotsitewise-assistant-conversation-id",
          (Option.map x.conversationId ~f:ConversationId.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let conversationId =
        (Option.map ~f:ConversationId.of_xml)
          (Xml.child xml_arg0 "x-amz-iotsitewise-assistant-conversation-id") in
      let body =
        (Option.map ~f:ResponseStream.of_xml) (Xml.child xml_arg0 "body") in
      make ?conversationId ?body ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let conversationId =
        field_map json__ "conversationId" ConversationId.of_json in
      let body = field_map json__ "body" ResponseStream.of_json in
      make ?conversationId ?body ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Invokes SiteWise Assistant to start or continue a conversation."]
